summaryPreview:
Remaining relevant evidence only:

### `include/simdjson/generic/ondemand/value-inl.h`
`value::at_pointer` no longer has an unconditional scalar/default `INVALID_JSON_POINTER`; it distinguishes leading `/` as `NO_SUCH_FIELD`.

```cpp
242: simdjson_inline simdjson_result<value> value::at_pointer(std::string_view json_pointer) noexcept {
243:   json_type t;
244:   SIMDJSON_TRY(type().get(t));
245:   switch (t)
246:   {
247:     case json_type::array:
248:       return (*this).get_array().at_pointer(json_pointer);
249:     case json_type::object:
250:       return (*this).get_object().at_pointer(json_pointer);
251:     default:
252:       return (!json_pointer.empty() && json_pointer[0] == '/') ? NO_SUCH_FIELD : INVALID_JSON_POINTER;
253:   }
254: }
```

